package ui.employer;
import javax.swing.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;
public class PostInternshipPanel extends JPanel{ JTextField title=UITheme.textField(),field=UITheme.textField(),city=UITheme.textField(),duration=UITheme.textField(),stipend=UITheme.textField(),deadline=UITheme.textField(); JComboBox<String> type=new JComboBox<>(new String[]{"Remote","On-site","Hybrid"}); JTextArea req=new JTextArea(),desc=new JTextArea(); public PostInternshipPanel(){ setBackground(UITheme.BG); setLayout(new GridLayout(0,1,0,6)); add(UITheme.title("Post Internship / Internship")); String[] labs={"Title","Field","City","Duration","Stipend","Deadline YYYY-MM-DD"}; JTextField[] fs={title,field,city,duration,stipend,deadline}; for(int i=0;i<labs.length;i++){add(UITheme.label(labs[i]));add(fs[i]);} add(UITheme.label("Type"));add(type); req.setBackground(UITheme.PANEL_2);req.setForeground(UITheme.TEXT); desc.setBackground(UITheme.PANEL_2);desc.setForeground(UITheme.TEXT); add(UITheme.label("Requirements"));add(new JScrollPane(req));add(UITheme.label("Description"));add(new JScrollPane(desc)); JButton post=UITheme.button("Post for Admin Approval");add(post); post.addActionListener(e->post());} void post(){ Employer emp=new EmployerDAO().getByUserId(Session.getUserId()); Company co=emp==null?null:new CompanyDAO().getByEmployerId(emp.getId()); if(co==null){DialogUtil.error(this,"Create company profile first.");return;} double st=0; try{st=Double.parseDouble(stipend.getText());}catch(Exception ex){} Internship j=new Internship(0,co.getId(),title.getText(),field.getText(),city.getText(),type.getSelectedItem().toString(),duration.getText(),st,req.getText(),desc.getText(),deadline.getText(),Constants.JOB_PENDING,null); DialogUtil.success(this,new InternshipController().post(j)?"Internship posted. Waiting for admin approval.":"Post failed");}}
